import {NgModule} from '@angular/core';
import {RouterModule, Routes} from '@angular/router';
import {HomePageComponent} from "./pages/home-page/home-page.component";
import {AdminLayoutComponent} from "./layout/admin-layout/admin-layout.component";
import {QuestionsListComponent} from "./domains/questions/components/questions-list/questions-list.component";
import {PollEditFormComponent} from "./domains/poll/components/poll-edit-form/poll-edit-form.component";
import {
  QuestionEditFormComponent
} from "./domains/questions/components/question-edit-form/question-edit-form.component";

const routes: Routes = [
  {path: '', component: HomePageComponent},
  {path: 'questions', component: QuestionsListComponent},
  {path: 'poll-form', component: PollEditFormComponent},
  {path: 'poll-form/:id', component: PollEditFormComponent},
  {path: 'question-form', component: QuestionEditFormComponent},
  {path: 'question-form/:id', component: QuestionEditFormComponent},
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})
export class AdminRoutingModule {
}
