import {Component, EventEmitter, Inject, OnInit, Output} from '@angular/core';
import {BaseComponent} from "../../../../../../base/components/base.component";
import {EventBusService} from "../../../../../../services/eventbus/event-bus.service";
import {Router} from "@angular/router";
import {SubscriptionContainerService} from "../../../../../../base/services/subscription-container.service";
import {FileUploadService} from "../../../../../../services/files/file-upload.service";
import {MAT_DIALOG_DATA, MatDialog, MatDialogRef} from "@angular/material/dialog";
import {NotifierService} from "../../../../../../services/notifier/notifier.service";
import {PollService} from "../../services/poll.service";
import {FormGroup} from "@angular/forms";
import {OptionService} from "../../services/option.service";
import {IUploadFile} from "../../../../../webapp/models/uploads/IUploadFile";
import {EventKey} from "../../../../../../services/eventbus/event.key";
import {IImageUploadResponse} from "../../../../../../models/IImageUploadResponse";

@Component({
  selector: 'app-poll-option-editform',
  templateUrl: './poll-option-editform.component.html',
  styleUrls: ['./poll-option-editform.component.scss']
})
export class PollOptionEditformComponent extends BaseComponent implements OnInit {
  @Output() formSubmitEvent: EventEmitter<boolean> = new EventEmitter<boolean>()
  pollOptionForm: FormGroup
  uploadFiles: IUploadFile[] = []


  protected componentName(): string {
    return "PollOptionEditformComponent";
  }

  constructor(
    eventBus: EventBusService,
    router: Router,
    subContainer: SubscriptionContainerService,
    private fileUploadService: FileUploadService,
    @Inject(MAT_DIALOG_DATA) public data: any,
    private optionService: OptionService,
    private notifier: NotifierService,
    public dialog: MatDialog,
    public dialogRef: MatDialogRef<PollOptionEditformComponent>,
  ) {
    super(eventBus, router, subContainer)
  }

  ngOnInit(): void {
    this.loading = false;
    this.pollOptionForm = this.optionService.getOptionForm(this.data)
  }

  removeImage(uf: IUploadFile) {
    let index = this.uploadFiles.map(file => file.previewUrl).indexOf(uf.previewUrl)
    this.uploadFiles.splice(index, 1)
  }

  onImageSelected(event: any) {
    if (event.target.files && event.target.files[0]) {
      // validate image
      const mimeType = event.target.files[0].type;
      if (mimeType.match(/image\/*/) == null) {
        this.notifier.warning("Unsupported", "Only images are supported.");
        return;
      }

      let uf: IUploadFile = {
        file: event.target.files[0],
        previewUrl: null
      }

      const reader = new FileReader();
      reader.readAsDataURL(event.target.files[0]);
      reader.onload = (e) => { // called once readAsDataURL is completed
        let url = e.target?.result
        if (url !== undefined && url !== null) {
          uf.previewUrl = url
          this.uploadFiles.push(uf);
        }
      }
    }
  }

  isInvalidFileCount(): boolean {
    return this.uploadFiles.length === 0
      || this.uploadFiles.length > 3
  }

  uploadImages(): void {
    this.loading = true

    let files: File[] = []
    this.uploadFiles.forEach(uf => {
      files.push(uf.file)
    });
    let key = this.componentKey(EventKey.FILES.IMAGE_UPLOAD(this.pollOptionForm.value.name + '-verif-img'))
    this.fileUploadService.uploadImages(key, files)
    this.subscribe(
      key,
      null,
      (value, meta) => {
        let imageResponses = <IImageUploadResponse[]>meta.data
        let images = imageResponses.map(r => r.image_url)
        this.closeDialog(images)
      }
    );

  }

  closeDialog(images: String[]) {
    this.pollOptionForm.controls['images'].setValue(images);
    if (!this.dialog.openDialogs || !this.dialog.openDialogs.length) {
      return;
    } else if (this.dialogRef.getState() == 0) {
      this.dialogRef.close(this.pollOptionForm.value);
    }
  }
}
