import {Inject, Injectable, LOCALE_ID} from '@angular/core';
import {BaseService} from "../../../../../base/services/base.service";
import {AuthService} from "../../../../common/modules/auth/services/auth.service";
import {NotifierService} from "../../../../../services/notifier/notifier.service";
import {HttpClient} from "@angular/common/http";
import {EventBusService} from "../../../../../services/eventbus/event-bus.service";
import {IParams} from "../../../../../base/endpoints/iparams";
import {IPage} from "../../../../../base/models/IPage";
import {WebAppEndpoint} from "../../../../webapp/web-app.endpoint";
import {IQuestion} from "../models/IQuestion";
import {IPoll} from "../../poll/models/ipoll";
import {FormBuilder, FormControl, Validators} from "@angular/forms";
import {formatDate} from "@angular/common";
import {PostService} from "../../poll/services/post.service";
import {QUESTIONS} from "../../../Common/Enums";

@Injectable({
  providedIn: 'root'
})
export class QuestionService extends BaseService {

  constructor(authService: AuthService,
              notifier: NotifierService,
              private http: HttpClient,
              private formBuilder: FormBuilder,
              @Inject(LOCALE_ID) public locale: string,
              private postService: PostService,
              private eventBusService: EventBusService) {
    super(authService, notifier);
  }

  fetchQuestions(key: string, params: IParams) {
    this.http.get<IPage<IQuestion>>(WebAppEndpoint.QUESTIONS.SEARCH(params))
      .subscribe((question: IPage<IQuestion>) => {
        this.eventBusService.publish(
          key,
          question
        )
      }, error => {
        this.eventBusService.publish(this.getErrorKey(key), error)
      })
  }

  getQuestionForm(exQuestion: IQuestion | undefined) {
    return exQuestion ? this.initializeForm(exQuestion) : this.createForm();
  }

  private initializeForm(question: IQuestion) {
    return this.formBuilder.group({
      id: new FormControl(question?.id),
      title: new FormControl(question?.title),
      type: new FormControl(question?.type),
      active_until: new FormControl(formatDate(question?.active_until, 'yyyy-MM-dd', this.locale)),
      post: this.postService.populatePostForm(question?.post),
    })
  }

  private createForm() {
    return this.formBuilder.group({
      title: new FormControl(null, [Validators.required]),
      type: new FormControl("ADMIN_MANAGED"),
      active_until: new FormControl(null),
      post: this.postService.getPostForm("QUESTION_SET"),
    })
  }

  getQuestionDetails(key: string, id: number) {
    this.http.get<IQuestion>(WebAppEndpoint.QUESTIONS.GET_DETAILS(id))
      .subscribe((question: IQuestion) => {
        this.eventBusService.publish(
          key,
          question
        )
      }, error => {
        this.eventBusService.publish(this.getErrorKey(key), error)
      })
  }

  createQuestion(key: string, question: IQuestion, images: string[]) {

    question.post.images = images
    question.active_until = new Date(question.active_until).toISOString()

    this.http.post<IQuestion>(WebAppEndpoint.QUESTIONS.CREATE(), question)
      .subscribe((que: IQuestion) => {
        this.eventBusService.publish(
          key,
          que
        )
      }, error => {
        this.eventBusService.publish(this.getErrorKey(key), error)
      })
  }

  updateQuestion(key: string, question: IQuestion, images: string[]) {
    question.post.images = images
    question.active_until = new Date(question.active_until).toISOString()
    this.http.patch<IQuestion>(WebAppEndpoint.QUESTIONS.UPDATE(question.id), question)
      .subscribe((que: IQuestion) => {
        this.eventBusService.publish(
          key,
          que
        )
      }, error => {
        this.eventBusService.publish(this.getErrorKey(key), error)
      })
  }

  private prepareObject(question: IQuestion) {
    return {
      id: question?.id,
      title: question?.title,
      type: question?.type,
      active_until: new Date(question.active_until).toISOString(),
      post: question?.post,
    }
  }
}
