import {Component, EventEmitter, Input, Output} from '@angular/core';
import {BaseComponent} from "../../../../../../base/components/base.component";
import {IPage} from "../../../../../../base/models/IPage";
import {IQuestion} from "../../../questions/models/IQuestion";
import {AuthService} from "../../../../../common/modules/auth/services/auth.service";
import {NotifierService} from "../../../../../../services/notifier/notifier.service";
import {EventBusService} from "../../../../../../services/eventbus/event-bus.service";
import {ActivatedRoute, Router} from "@angular/router";
import {SubscriptionContainerService} from "../../../../../../base/services/subscription-container.service";
import {QuestionService} from "../../../questions/services/question.service";
import {IParams} from "../../../../../../base/endpoints/iparams";
import {EventKey} from "../../../../../../services/eventbus/event.key";
import {MetaData} from "ng-event-bus/lib/meta-data";
import {PageEvent} from "@angular/material/paginator";
import {IPoll} from "../../models/ipoll";
import {PollService} from "../../services/poll.service";
import {MatDialog} from "@angular/material/dialog";
import {PollEditFormComponent} from "../poll-edit-form/poll-edit-form.component";

@Component({
  selector: 'app-poll-list',
  templateUrl: './poll-list.component.html',
  styleUrls: ['./poll-list.component.scss']
})
export class PollListComponent extends BaseComponent {
  size = 10;
  page: number = 1;
  polls: IPage<IPoll> | undefined
  @Input() questionSetId: number | undefined
  @Output() pollLoaded: EventEmitter<boolean> = new EventEmitter<boolean>()

  constructor(private authService: AuthService,
              private notifier: NotifierService,
              eventBus: EventBusService,
              router: Router,
              subContainer: SubscriptionContainerService,
              private dialog: MatDialog,
              private pollService: PollService) {
    super(eventBus, router, subContainer)

  }


  protected componentName(): string {
    return "PollListComponent";
  }

  ngOnInit(): void {
    this.getPollList({
      page: 0,
      size: this.size,
      question_set_id: this.questionSetId
    })
  }

  private getPollList(params: IParams) {
    this.loading = true
    const key = this.componentKey(EventKey.POLLS.SEARCH())
    this.pollService.fetchPolls(key, params)
    this.subscribe(
      key,
      null,
      (value: Boolean, meta: MetaData) => {
        this.polls = meta.data
        this.loading = false
        this.pollLoaded.emit(true)
      })
    this.subscribe(this.getErrorKey(key), null, (value, meta) => {
      this.notifier.log(meta.data)
    })
  }

  onChange(event: PageEvent) {
    console.log(event);
    this.getPollList({
      page: event.pageIndex,
      size: this.size
    })
  }


  openEditForm(id: number | null) {
    const dialogRef = this.dialog.open(PollEditFormComponent, {
      width: '500px',
      height: '500px',
      data: {
        questionId: this.questionSetId,
        id: id
      },
    })

    let instance = dialogRef.componentInstance
    instance.formSubmitEvent.subscribe((v: boolean) => {
      dialogRef.close()
    })

    dialogRef.afterClosed().subscribe(result => {
      this.reloadRoute()
    })
  }
}
