import {Component, EventEmitter, Input, OnInit, Output} from '@angular/core';
import {BaseComponent} from "../../../../../../base/components/base.component";
import {FormGroup} from "@angular/forms";
import {IPollOption} from "../../../poll/models/ipoll-option";
import {IPage} from "../../../../../../base/models/IPage";
import {IPoll} from "../../../poll/models/ipoll";
import {EventBusService} from "../../../../../../services/eventbus/event-bus.service";
import {ActivatedRoute, Router} from "@angular/router";
import {SubscriptionContainerService} from "../../../../../../base/services/subscription-container.service";
import {NotifierService} from "../../../../../../services/notifier/notifier.service";
import {PollService} from "../../../poll/services/poll.service";
import {OptionService} from "../../../poll/services/option.service";
import {IQuestion} from "../../models/IQuestion";
import {QuestionService} from "../../services/question.service";
import {EventKey} from "../../../../../../services/eventbus/event.key";
import {MetaData} from "ng-event-bus/lib/meta-data";
import {HttpErrorResponse} from "@angular/common/http";
import {POSTS, QUESTIONS} from "../../../../Common/Enums";
import {IUploadFile} from "../../../../../webapp/models/uploads/IUploadFile";
import {FileUploadService} from "../../../../../../services/files/file-upload.service";
import {IImageUploadResponse} from "../../../../../../models/IImageUploadResponse";

@Component({
  selector: 'app-question-edit-form',
  templateUrl: './question-edit-form.component.html',
  styleUrls: ['./question-edit-form.component.scss']
})
export class QuestionEditFormComponent extends BaseComponent implements OnInit {

  questionForm: FormGroup
  @Input() exQuestion: IQuestion | undefined
  questionType: string[] = QUESTIONS.TYPE
  postType: string[] = POSTS.TYPE
  @Output() questionOptionLoaded: EventEmitter<boolean> = new EventEmitter<boolean>()
  uploadFiles: IUploadFile[] = []
  paramId: number | undefined
  minStartDate: Date = new Date();
  end_date: any;


  constructor(
    eventBus: EventBusService,
    router: Router,
    route: ActivatedRoute,
    subContainer: SubscriptionContainerService,
    private fileUploadService: FileUploadService,
    private notifier: NotifierService,
    private questionService: QuestionService,
  ) {
    super(eventBus, router, subContainer)
    this.getQuestionDetails(route.snapshot.params['id'])
  }

  protected componentName(): string {
    return "QuestionEditFormComponent";
  }

  ngOnInit(): void {
    this.loading = false;
    this.questionForm = this.questionService.getQuestionForm(this.exQuestion)
  }

  private getQuestionDetails(param: number | undefined) {
    if (param) {
      this.paramId = param
      this.loading = true
      const key = this.componentKey(EventKey.QUESTIONS.GET_DETAILS(param))
      this.questionService.getQuestionDetails(key, param)
      this.subscribe(
        key,
        null,
        (value: Boolean, meta: MetaData) => {
          this.exQuestion = meta.data
          this.end_date = new Date(meta.data.active_until)
          this.questionForm = this.questionService.getQuestionForm(this.exQuestion)
          this.loading = false
        })
      this.subscribe(this.getErrorKey(key), null, (value, meta) => {
        this.notifier.log(meta.data)
      })
    }
  }

  createQuestion(images: string[]) {
    let key = this.componentKey(EventKey.POLLS.CREATE(this.questionForm.value.name))
    if (this.questionForm.value.id) {
      this.questionService.updateQuestion(key, this.questionForm.value, images)
    } else {
      this.questionService.createQuestion(key, this.questionForm.value, images)
    }
    this.subscribe(key, null, (value, meta) => {
      this.loading = false;
      this.notifier.success("Success", "Poll created")
      this.questionForm.reset();
      this.uploadFiles = []
      this.navigate("admin/question-form/" + meta.data.id, value => {
        this.reloadRoute()
      })
    })
    this.subscribe(this.getErrorKey(key), null, (value, meta) => {
      let error: HttpErrorResponse = meta.data
      this.loading = false;
      this.notifier.warning('Failed!', error.error.message)
    })
  }

  addTag(tag: string) {
    return tag;
  }

  removeImage(uf: IUploadFile) {
    let index = this.uploadFiles.map(file => file.previewUrl).indexOf(uf.previewUrl)
    this.uploadFiles.splice(index, 1)
  }

  onImageSelected(event: any) {
    if (event.target.files && event.target.files[0]) {
      // validate image
      const mimeType = event.target.files[0].type;
      if (mimeType.match(/image\/*/) == null) {
        this.notifier.warning("Unsupported", "Only images are supported.");
        return;
      }

      let uf: IUploadFile = {
        file: event.target.files[0],
        previewUrl: null
      }

      const reader = new FileReader();
      reader.readAsDataURL(event.target.files[0]);
      reader.onload = (e) => { // called once readAsDataURL is completed
        let url = e.target?.result
        if (url !== undefined && url !== null) {
          uf.previewUrl = url
          this.uploadFiles.push(uf);
        }
      }
    }
  }

  isInvalidFileCount(): boolean {
    return this.uploadFiles.length === 0
      || this.uploadFiles.length > 3
  }

  uploadImages(): void {
    this.loading = true

    let files: File[] = []
    this.uploadFiles.forEach(uf => {
      files.push(uf.file)
    });
    let key = this.componentKey(EventKey.FILES.IMAGE_UPLOAD(this.questionForm.value.name + '-verif-img'))
    this.fileUploadService.uploadImages(key, files)
    this.subscribe(
      key,
      null,
      (value, meta) => {
        let imageResponses = <IImageUploadResponse[]>meta.data
        let images = imageResponses.map(r => r.image_url)
        this.createQuestion(images)
      }
    );

  }

  selectEndDate() {
    if (this.end_date != null) {
      this.questionForm.controls['active_until'].setValue(new Date(this.end_date).toISOString());
    } else {
      this.questionForm.controls['active_until'].setValue(null);
    }
  }

}
