import {Inject, Injectable, LOCALE_ID} from '@angular/core';
import {BaseService} from "../../../../../base/services/base.service";
import {AuthService} from "../../../../common/modules/auth/services/auth.service";
import {NotifierService} from "../../../../../services/notifier/notifier.service";
import {HttpClient, HttpErrorResponse} from "@angular/common/http";
import {EventBusService} from "../../../../../services/eventbus/event-bus.service";
import {IParams} from "../../../../../base/endpoints/iparams";
import {IPage} from "../../../../../base/models/IPage";
import {IQuestion} from "../../questions/models/IQuestion";
import {WebAppEndpoint} from "../../../../webapp/web-app.endpoint";
import {IPoll} from "../models/ipoll";
import {FormArray, FormBuilder, FormControl, FormGroup, Validators} from "@angular/forms";
import {IPost} from "../../questions/models/IPost";
import {PostService} from "./post.service";
import {OptionService} from "./option.service";
import {formatDate} from "@angular/common";
import {IRedeem} from "../../../../webapp/models/leaderboard/redeem.model";
import {BaseEndpoint} from "../../../../../base/endpoints/base.endpoint";
import {DateUtil} from "../../../../../utils/date.util";

@Injectable({
  providedIn: 'root'
})
export class PollService extends BaseService {

  constructor(authService: AuthService,
              notifier: NotifierService,
              private http: HttpClient,
              private formBuilder: FormBuilder,
              private eventBusService: EventBusService,
              private postService: PostService,
              private optionService: OptionService,
              @Inject(LOCALE_ID) public locale: string
  ) {
    super(authService, notifier);
  }

  fetchPolls(key: string, params: IParams) {
    let url = WebAppEndpoint.POLLS.SEARCH(params)
    if (params['question_set_id']) {
      url = WebAppEndpoint.POLLS.SEARCH_ADMIN(params)
    }
    this.http.get<IPage<IPoll>>(url)
      .subscribe((poll: IPage<IPoll>) => {
        this.eventBusService.publish(
          key,
          poll
        )
      }, error => {
        this.eventBusService.publish(this.getErrorKey(key), error)
      })
  }

  getPollDetails(key: string, id: number) {
    this.http.get<IPoll>(WebAppEndpoint.POLLS.GET_DETAILS(id))
      .subscribe((poll: IPoll) => {
        this.eventBusService.publish(
          key,
          poll
        )
      }, error => {
        this.eventBusService.publish(this.getErrorKey(key), error)
      })
  }

  createPoll(key: string, poll: IPoll, images: string[]) {
    poll.active_from = this.getTimeAfterFiveMinutes(poll.active_from)
    poll.active_until = DateUtil.getIsoFormatDate(poll.active_until)
    poll.post.images = images

    this.http.post<IPoll>(WebAppEndpoint.POLLS.CREATE(), poll)
      .subscribe((poll: IPoll) => {
        this.eventBusService.publish(
          key,
          poll
        )
      }, error => {
        this.eventBusService.publish(this.getErrorKey(key), error)
      })
  }

  updatePoll(key: string, poll: IPoll, images: string[]) {
    poll.active_from = this.getTimeAfterFiveMinutes(poll.active_from)
    poll.active_until = DateUtil.getIsoFormatDate(poll.active_until)
    poll.post.images = images
    this.http.patch<IPoll>(WebAppEndpoint.POLLS.UPDATE(poll.id), poll)
      .subscribe((poll: IPoll) => {
        this.eventBusService.publish(
          key,
          poll
        )
      }, error => {
        this.eventBusService.publish(this.getErrorKey(key), error)
      })
  }

  getPollEditForm(exPoll: IPoll | undefined, questionId: number | undefined) {
    return exPoll ? this.initializeForm(exPoll) : this.createForm(questionId);
  }

  private initializeForm(exPoll: IPoll) {
    return this.formBuilder.group({
      id: new FormControl(exPoll?.id),
      title: new FormControl(exPoll?.title),
      active_from: new FormControl(formatDate(exPoll?.active_from, 'yyyy-MM-dd', this.locale)),
      active_until: new FormControl(formatDate(exPoll?.active_until, 'yyyy-MM-dd', this.locale)),
      post: this.postService.populatePostForm(exPoll?.post),
      multiple_choice: new FormControl(exPoll?.multiple_choice),
      options: new FormControl(exPoll?.options),
      correct_options: new FormControl(exPoll?.correct_options),
      question_set_id: new FormControl(exPoll?.question_set_id),
    })
  }

  private createForm(questionId: any) {
    return this.formBuilder.group({
      title: new FormControl(null, [Validators.required]),
      active_from: new FormControl(null),
      active_until: new FormControl(null),
      post: this.postService.getPostForm("POLL"),
      multiple_choice: new FormControl(null),
      options: new FormControl(),
      correct_options: new FormControl([]),
      question_set_id: new FormControl(questionId ? questionId : null),
    })
  }

  private prepareObject(poll: IPoll) {
    return {
      id: poll?.id,
      title: poll?.title,
      active_from: new Date(poll.active_from).toISOString(),
      active_until: new Date(poll.active_until).toISOString(),
      post: poll?.post,
      multiple_choice: poll?.multiple_choice,
      options: poll?.options,
      correct_options: poll?.correct_options,
      question_set_id: poll?.question_set_id,
    }
  }


  private getTimeAfterFiveMinutes(date: string) {
    let fromDate;
    if (date == null) fromDate = new Date()
    else
      fromDate = new Date(date)
    fromDate.setMinutes(new Date().getMinutes() + 4);
    return fromDate.toISOString()
  }
}

