import {Component, EventEmitter, Output} from '@angular/core';
import {BaseComponent} from "../../../../../../base/components/base.component";
import {AuthService} from "../../../../../common/modules/auth/services/auth.service";
import {NotifierService} from "../../../../../../services/notifier/notifier.service";
import {EventBusService} from "../../../../../../services/eventbus/event-bus.service";
import {Router} from "@angular/router";
import {SubscriptionContainerService} from "../../../../../../base/services/subscription-container.service";
import {ProductService} from "../../../../../webapp/services/product.service";
import {IParams} from "../../../../../../base/endpoints/iparams";
import {QuestionService} from "../../services/question.service";
import {EventKey} from "../../../../../../services/eventbus/event.key";
import {MetaData} from "ng-event-bus/lib/meta-data";
import {IProductSlice} from "../../../../../webapp/models/inventory/product-slice.model";
import {IQuestion} from "../../models/IQuestion";
import {IPage} from "../../../../../../base/models/IPage";
import {PageEvent} from "@angular/material/paginator";
import {IPoll} from "../../../poll/models/ipoll";

@Component({
  selector: 'app-questions-list',
  templateUrl: './questions-list.component.html',
  styleUrls: ['./questions-list.component.scss']
})
export class QuestionsListComponent extends BaseComponent {
  size = 10;
  page: number = 1;
  search_key: string = '';
  questions: IPage<IQuestion> | undefined
  @Output() questionLoaded: EventEmitter<boolean> = new EventEmitter<boolean>()

  constructor(private authService: AuthService,
              private notifier: NotifierService,
              eventBus: EventBusService,
              router: Router,
              subContainer: SubscriptionContainerService,
              private questionService: QuestionService) {
    super(eventBus, router, subContainer)
  }


  protected componentName(): string {
    return "QuestionsListComponent";
  }

  ngOnInit(): void {
    this.getQuestions({
      page: 0,
      size: this.size
    })
  }

  private getQuestions(params: IParams) {
    this.loading = true
    const key = this.componentKey(EventKey.QUESTIONS.SEARCH())
    this.questionService.fetchQuestions(key, params)
    this.subscribe(
      key,
      null,
      (value: Boolean, meta: MetaData) => {
        this.questions = meta.data
        this.loading = false
        this.questionLoaded.emit(true)
      })
    this.subscribe(this.getErrorKey(key), null, (value, meta) => {
      this.notifier.log(meta.data)
    })
  }

  onChange(event: PageEvent) {
    console.log(event);
    this.getQuestions({
      page: event.pageIndex,
      size: this.size
    })
  }

  updateQuestion(question: IQuestion) {
    this.navigate('admin/question-form/' + question.id, value => {
    })
  }
}
